//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageverifyimport("reflect""testing""time""github.com/hashicorp/terraform-provider-aws/internal/flex")funcTestSuppressEquivalentRoundedTime(t*testing.T){t.Parallel()testCases:=[]struct{oldstringnewstringlayoutstringdtime.Durationequivalentbool}{{old:"2024-04-19T23:00:00.000Z",new:"2024-04-19T23:00:13.000Z",layout:time.RFC3339,d:time.Minute,equivalent:true,},{old:"2024-04-19T23:01:00.000Z",new:"2024-04-19T23:00:45.000Z",layout:time.RFC3339,d:time.Minute,equivalent:true,},{old:"2024-04-19T23:00:00.000Z",new:"2024-04-19T23:00:45.000Z",layout:time.RFC3339,d:time.Minute,equivalent:false,},{old:"2024-04-19T23:00:00.000Z",new:"2024-04-19T23:00:45.000Z",layout:time.RFC3339,d:time.Hour,equivalent:true,},}fori,tc:=rangetestCases{value:=SuppressEquivalentRoundedTime(tc.layout,tc.d)("test_property",tc.old,tc.new,nil)iftc.equivalent&&!value{t.Fatalf("expectedtestcase%dtobeequivalent",i)}if!tc.equivalent&&value{t.Fatalf("expectedtestcase%dtonotbeequivalent",i)}}}funcTestDiffStringMaps(t*testing.T){t.Parallel()cases:=[]struct{Old,Newmap[string]interface{}Create,Remove,Unchangedmap[string]interface{}}{//Add{Old:map[string]interface{}{"foo":"bar",},New:map[string]interface{}{"foo":"bar","bar":"baz",},Create:map[string]interface{}{"bar":"baz",},Remove:map[string]interface{}{},Unchanged:map[string]interface{}{"foo":"bar",},},//Modify{Old:map[string]interface{}{"foo":"bar",},New:map[string]interface{}{"foo":"baz",},Create:map[string]interface{}{"foo":"baz",},Remove:map[string]interface{}{"foo":"bar",},Unchanged:map[string]interface{}{},},//Overlap{Old:map[string]interface{}{"foo":"bar","hello":"world",},New:map[string]interface{}{"foo":"baz","hello":"world",},Create:map[string]interface{}{"foo":"baz",},Remove:map[string]interface{}{"foo":"bar",},Unchanged:map[string]interface{}{"hello":"world",},},//Remove{Old:map[string]interface{}{"foo":"bar","bar":"baz",},New:map[string]interface{}{"foo":"bar",},Create:map[string]interface{}{},Remove:map[string]interface{}{"bar":"baz",},Unchanged:map[string]interface{}{"foo":"bar",},},}fori,tc:=rangecases{c,r,u:=DiffStringMaps(tc.Old,tc.New)cm:=flex.PointersMapToStringList(c)rm:=flex.PointersMapToStringList(r)um:=flex.PointersMapToStringList(u)if!reflect.DeepEqual(cm,tc.Create){t.Fatalf("%d:badcreate:%#v",i,cm)}if!reflect.DeepEqual(rm,tc.Remove){t.Fatalf("%d:badremove:%#v",i,rm)}if!reflect.DeepEqual(um,tc.Unchanged){t.Fatalf("%d:badunchanged:%#v",i,rm)}}}